    /// The amount of the shape's own material one item represents (`GTValues.M` = one ingot), or
    /// -1 for a shape this registry has no data for.
    public static long materialAmount(String shapeName) {
        return MATERIAL_AMOUNT.getOrDefault(shapeName, -1L);
    }

    public static long materialAmount(Shape shape) {
        return materialAmount(shape.getName());
    }

    /// The secondary material and amount consumed alongside the shape's own material (e.g. the
    /// tin plates a cell is stamped from), or null when the shape has none.
    public static MaterialRefStack secondaryMaterial(String shapeName) {
        return SECONDARY_MATERIAL.get(shapeName);
    }

    public static MaterialRefStack secondaryMaterial(Shape shape) {
        return secondaryMaterial(shape.getName());
    }

    public static int defaultStackSize(String shapeName) {
        return DEFAULT_STACK_SIZE.getOrDefault(shapeName, 64);
    }

    public static int defaultStackSize(Shape shape) {
        return defaultStackSize(shape.getName());
    }

    public static boolean isRecyclable(String shapeName) {
        return RECYCLABLE.getOrDefault(shapeName, false);
    }

    public static boolean isRecyclable(Shape shape) {
        return isRecyclable(shape.getName());
    }

    public static boolean isEnchantable(String shapeName) {
        return ENCHANTABLE.getOrDefault(shapeName, false);
    }

    public static boolean isEnchantable(Shape shape) {
        return isEnchantable(shape.getName());
    }

    public static boolean isUnifiable(String shapeName) {
        return UNIFIABLE.getOrDefault(shapeName, false);
    }

    public static boolean isUnifiable(Shape shape) {
        return isUnifiable(shape.getName());
    }

